import{_ as e,o,c as i,a2 as r}from"./chunks/framework.Bk_3gXAz.js";const p=JSON.parse('{"title":"jobs-to-be-done","description":"Discover what customers truly need by analyzing the \\"job\\" they hire your product to do. Use when the user mentions \\"customer discovery\\", \\"why customers churn\\", \\"what job does this solve\\", \\"competing against luck\\", or \\"product-market fit\\". Covers JTBD interviews, competition analysis, and jobs-oriented roadmaps. For product positioning, see obviously-awesome. For rapid validation, see design-sprint.","frontmatter":{"title":"jobs-to-be-done","name":"jobs-to-be-done","description":"Discover what customers truly need by analyzing the \\"job\\" they hire your product to do. Use when the user mentions \\"customer discovery\\", \\"why customers churn\\", \\"what job does this solve\\", \\"competing against luck\\", or \\"product-market fit\\". Covers JTBD interviews, competition analysis, and jobs-oriented roadmaps. For product positioning, see obviously-awesome. For rapid validation, see design-sprint.","license":"MIT","metadata":{"author":"wondelai","version":"1.1.1"}},"headers":[],"relativePath":"skills/jobs-to-be-done.md","filePath":"skills/jobs-to-be-done.md"}'),n={name:"skills/jobs-to-be-done.md"};function a(s,t,d,u,c,l){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="jobs-to-be-done-framework" tabindex="-1">Jobs to Be Done Framework <a class="header-anchor" href="#jobs-to-be-done-framework" aria-label="Permalink to &quot;Jobs to Be Done Framework&quot;">​</a></h1><p>Framework for discovering innovation based on a fundamental truth: customers don&#39;t buy products - they &quot;hire&quot; them to do a specific job in their lives.</p><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><p><strong>Job to Be Done</strong> = the progress a customer wants to make in specific circumstances.</p><p>Key elements of the definition:</p><ul><li><strong>Progress</strong> (not goal, not solution) - customer wants to move from current state to a better one</li><li><strong>Circumstances</strong> - context determines the job, not customer attributes (demographics are useless)</li><li><strong>Hiring/Firing</strong> - customer actively chooses a product for the &quot;job&quot;</li></ul><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p><strong>Goal: 10/10.</strong> When reviewing or creating product strategy or positioning, rate it 0-10 based on adherence to the principles below. A 10/10 means full alignment with all guidelines; lower scores indicate gaps to address. Always provide the current score and specific improvements needed to reach 10/10.</p><h2 id="three-dimensions-of-every-job" tabindex="-1">Three Dimensions of Every Job <a class="header-anchor" href="#three-dimensions-of-every-job" aria-label="Permalink to &quot;Three Dimensions of Every Job&quot;">​</a></h2><p>Every job has three inseparable dimensions - omitting any means failure:</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Question</th><th>Example (milkshake)</th></tr></thead><tbody><tr><td><strong>Functional</strong></td><td>What does the customer need to do?</td><td>Occupy myself during boring commute</td></tr><tr><td><strong>Emotional</strong></td><td>How do they want to feel?</td><td>Have a small treat for myself</td></tr><tr><td><strong>Social</strong></td><td>How do they want to be perceived?</td><td>As a sensible parent (not buying donuts)</td></tr></tbody></table><h2 id="framework" tabindex="-1">Framework <a class="header-anchor" href="#framework" aria-label="Permalink to &quot;Framework&quot;">​</a></h2><h3 id="_1-the-job-statement" tabindex="-1">1. The Job Statement <a class="header-anchor" href="#_1-the-job-statement" aria-label="Permalink to &quot;1. The Job Statement&quot;">​</a></h3><p><strong>Core concept:</strong> A job statement captures the progress a customer seeks in a specific circumstance, expressed in a structured format that separates context, desired progress, and expected outcome.</p><p><strong>Why it works:</strong> By forcing teams to articulate the job in the customer&#39;s language and circumstances, it prevents solution-first thinking and keeps innovation grounded in real human progress.</p><p><strong>Key insights:</strong></p><ul><li>The format is: &quot;When [circumstances], I want to [progress], so I can [outcome]&quot;</li><li>Circumstances matter more than customer demographics - the same person has different jobs in different situations</li><li>A well-written job statement never mentions your product or any specific solution</li><li>Jobs are stable over time; solutions change but the underlying job persists</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>New product ideation</td><td>Define the job before brainstorming features</td><td>&quot;When I&#39;m commuting alone, I want something to occupy me and satisfy hunger, so I&#39;m not hungry until lunch&quot;</td></tr><tr><td>Feature prioritization</td><td>Evaluate whether a feature serves the core job</td><td>Prioritize features that help accomplish the stated job over nice-to-have additions</td></tr><tr><td>Positioning &amp; messaging</td><td>Use the job statement language in marketing copy</td><td>Lead with the circumstance and desired progress, not product specs</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;When you&#39;re [circumstance], you need [progress] -- that&#39;s exactly what [product] does&quot;</li><li>Lead with the situation the customer recognizes, not the product category</li><li>Mirror the emotional and social dimensions alongside the functional one</li></ul><p><strong>Ethical boundary:</strong> Never fabricate or exaggerate circumstances to manufacture urgency. The job must reflect genuine customer progress, not artificially created anxiety.</p><p>See: <a href="./references/innovation-process">references/innovation-process.md</a></p><h3 id="_2-forces-of-progress-push-pull-anxiety-habit" tabindex="-1">2. Forces of Progress (Push, Pull, Anxiety, Habit) <a class="header-anchor" href="#_2-forces-of-progress-push-pull-anxiety-habit" aria-label="Permalink to &quot;2. Forces of Progress (Push, Pull, Anxiety, Habit)&quot;">​</a></h3><p><strong>Core concept:</strong> The decision to &quot;hire&quot; a new product results from the interplay of four forces: Push (frustration with current situation), Pull (attraction of new solution), Anxiety (fear of the new), and Habit (comfort with current behavior). Change only happens when Push + Pull &gt; Habit + Anxiety.</p><p><strong>Why it works:</strong> Most innovation efforts focus only on making the product better (increasing Pull), but ignore the equally powerful anti-change forces. Understanding all four forces reveals why great products still fail to gain adoption.</p><p><strong>Key insights:</strong></p><ul><li>Push is frustration with the current situation (&quot;this annoys me&quot;)</li><li>Pull is the attraction of a new solution (&quot;I want this&quot;)</li><li>Habit is attachment to current behavior (&quot;I&#39;ve always done it this way&quot;)</li><li>Anxiety is fear of the new (&quot;what if it doesn&#39;t work?&quot;)</li><li>Often it&#39;s more effective to reduce anxiety and habit than to increase push and pull</li><li>Passive seekers (vaguely aware of a problem) are easier to influence than active seekers who already have criteria</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Onboarding design</td><td>Reduce anxiety with free trials, guarantees, and social proof</td><td>Money-back guarantee addresses &quot;what if it doesn&#39;t work?&quot; anxiety</td></tr><tr><td>Switching campaigns</td><td>Address habit directly by making migration effortless</td><td>One-click data import from competitor reduces habit friction</td></tr><tr><td>Content marketing</td><td>Awaken push in passive seekers by naming their frustration</td><td>Blog post: &quot;5 signs your current tool is costing you hours every week&quot;</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>Address anxiety directly: &quot;No lock-in, cancel anytime, your data is always yours&quot;</li><li>Name the push: &quot;Tired of [frustration]? There&#39;s a better way&quot;</li><li>Reduce habit friction: &quot;Switch in 5 minutes -- we import everything automatically&quot;</li></ul><p><strong>Ethical boundary:</strong> Never manufacture artificial push by exaggerating pain or creating fear. Reducing real anxiety is ethical; creating new anxiety to drive sales is manipulation.</p><p>See: <a href="./references/competitive-strategy">references/competitive-strategy.md</a></p><h3 id="_3-the-big-hire-little-hire" tabindex="-1">3. The Big Hire &amp; Little Hire <a class="header-anchor" href="#_3-the-big-hire-little-hire" aria-label="Permalink to &quot;3. The Big Hire &amp; Little Hire&quot;">​</a></h3><p><strong>Core concept:</strong> There are two distinct decision moments: the Big Hire (purchase/signup decision, happens once) and the Little Hire (decision to use in the moment, happens repeatedly). Winning the Big Hire does not guarantee the Little Hire.</p><p><strong>Why it works:</strong> Many products win the sale but lose the customer because they optimize only for the purchase decision and neglect the repeated usage decision. Understanding both moments reveals where retention problems truly originate.</p><p><strong>Key insights:</strong></p><ul><li>Big Hire is driven by marketing, onboarding, and first impressions</li><li>Little Hire is driven by product quality, UX, and ongoing value delivery</li><li>Many products lose at the Little Hire stage -- purchased but never used</li><li>The forces of progress operate differently at each stage: Big Hire anxiety is about the purchase risk; Little Hire anxiety is about effort and learning curves</li><li>Retention problems are almost always Little Hire failures, not Big Hire failures</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Retention analysis</td><td>Distinguish Big Hire metrics from Little Hire metrics</td><td>Track &quot;first use after signup&quot; and &quot;weekly active usage&quot; separately from signup conversion</td></tr><tr><td>Product design</td><td>Optimize the repeated usage experience, not just first impression</td><td>Reduce friction in daily workflows even if onboarding is already smooth</td></tr><tr><td>Customer success</td><td>Monitor Little Hire signals to predict churn</td><td>Declining usage frequency is a Little Hire failure signaling upcoming churn</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>Big Hire copy focuses on the promise: &quot;Transform how you [job]&quot;</li><li>Little Hire copy focuses on ease: &quot;One click and you&#39;re done&quot;</li><li>Re-engagement copy addresses Little Hire failure: &quot;We&#39;ve made [specific friction] easier&quot;</li></ul><p><strong>Ethical boundary:</strong> Never design dark patterns that win the Big Hire (e.g., hidden fees, misleading trials) while failing the Little Hire. Both decisions must deliver genuine progress.</p><p>See: <a href="./references/case-studies">references/case-studies.md</a></p><h3 id="_4-competitive-landscape-non-obvious-competition" tabindex="-1">4. Competitive Landscape (Non-Obvious Competition) <a class="header-anchor" href="#_4-competitive-landscape-non-obvious-competition" aria-label="Permalink to &quot;4. Competitive Landscape (Non-Obvious Competition)&quot;">​</a></h3><p><strong>Core concept:</strong> True competition is everything a customer can &quot;hire&quot; for the same job, often from completely different product categories. Competitors are defined by the job, not by industry classification.</p><p><strong>Why it works:</strong> Analyzing competition through product categories creates blind spots. A milkshake competes with bananas, bagels, boredom, and podcasts. Netflix competes with TikTok, sleep, family conversation, and games. By mapping the full competitive landscape around the job, teams spot threats and opportunities invisible to traditional analysis.</p><p><strong>Key insights:</strong></p><ul><li>Non-consumption (doing nothing) is often the biggest competitor</li><li>Workarounds and compensating behaviors reveal unserved jobs: people hack, combine, and improvise solutions</li><li>Online courses compete with books, YouTube, mentoring, and doing nothing</li><li>Integration is needed when performance is &quot;not good enough&quot; for the job; modularization when it&#39;s &quot;good enough&quot;</li><li>The best competitive positioning answers &quot;what job are we the best hire for?&quot; not &quot;how do we compare to similar products?&quot;</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Competitive analysis</td><td>Map all hires for the same job across categories</td><td>A project management tool competes with spreadsheets, sticky notes, email threads, and memory</td></tr><tr><td>Positioning strategy</td><td>Position against the real alternative, not the obvious one</td><td>Position against &quot;doing it manually&quot; rather than against a named competitor</td></tr><tr><td>Pricing strategy</td><td>Price relative to the job&#39;s value, not competitor pricing</td><td>If the job saves 10 hours per week, price against the value of that time, not against similar SaaS products</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Stop using [workaround] for [job] -- there&#39;s a purpose-built solution&quot;</li><li>&quot;You wouldn&#39;t hire a [bad fit] to [job] -- so why are you using [current hack]?&quot;</li><li>Position around the job outcome, not feature comparison charts</li></ul><p><strong>Ethical boundary:</strong> Never misrepresent competitors or create false equivalences. Honest competitive framing based on the job is powerful; distorting alternatives is deceptive.</p><p>See: <a href="./references/competitive-strategy">references/competitive-strategy.md</a></p><h3 id="_5-customer-discovery-interviews" tabindex="-1">5. Customer Discovery Interviews <a class="header-anchor" href="#_5-customer-discovery-interviews" aria-label="Permalink to &quot;5. Customer Discovery Interviews&quot;">​</a></h3><p><strong>Core concept:</strong> Don&#39;t ask customers directly &quot;what do you need&quot; -- they don&#39;t know. Instead, investigate the purchase timeline by reconstructing the moments of first thought, search, purchase, and usage to uncover the real job.</p><p><strong>Why it works:</strong> Customers rationalize decisions after the fact and can&#39;t articulate latent needs. By walking backward through the concrete events of their decision journey, you uncover the true circumstances, forces, and tradeoffs that drove their behavior.</p><p><strong>Key insights:</strong></p><ul><li>First thought questions: &quot;When did you first think about looking for a solution?&quot;, &quot;What was happening in your life then?&quot;, &quot;What was frustrating you?&quot;</li><li>Search questions: &quot;What alternatives did you look for?&quot;, &quot;What eliminated options?&quot;, &quot;Who did you talk to about this decision?&quot;</li><li>Purchase moment questions: &quot;Where were you?&quot;, &quot;What ultimately convinced you?&quot;, &quot;What were you afraid of?&quot;</li><li>Usage questions: &quot;Is the product doing what you expected?&quot;, &quot;What surprised you?&quot;, &quot;What&#39;s still missing?&quot;</li><li>Signals of undiscovered jobs: workarounds, non-consumption, compensating behaviors, negative emotions with current solutions</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>New market entry</td><td>Interview people who recently switched to or from a competitor</td><td>Reconstruct the timeline to find what pushed them away and pulled them toward the new solution</td></tr><tr><td>Churn reduction</td><td>Interview churned customers about their decision timeline</td><td>Discover whether the failure was Big Hire (wrong expectations) or Little Hire (poor daily experience)</td></tr><tr><td>Feature discovery</td><td>Interview customers using workarounds</td><td>A customer using spreadsheets alongside your product reveals an unmet job dimension</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>Use exact customer language from interviews in marketing copy</li><li>&quot;We heard you say [verbatim quote] -- so we built [feature]&quot;</li><li>Frame benefits using the circumstances and emotions customers actually described</li></ul><p><strong>Ethical boundary:</strong> Never lead interview subjects toward predetermined conclusions. The goal is genuine discovery, not confirmation of existing assumptions.</p><p>See: <a href="./references/innovation-process">references/innovation-process.md</a></p><h3 id="_6-designing-for-the-job" tabindex="-1">6. Designing for the Job <a class="header-anchor" href="#_6-designing-for-the-job" aria-label="Permalink to &quot;6. Designing for the Job&quot;">​</a></h3><p><strong>Core concept:</strong> Build the entire product experience -- features, metrics, and organization -- around helping the customer accomplish their job, not around internal capabilities or competitive feature parity.</p><p><strong>Why it works:</strong> When every product decision answers &quot;will this help the customer better accomplish their job?&quot;, teams avoid feature bloat, build coherent experiences, and create products that customers genuinely value. If you can&#39;t answer the question, you don&#39;t understand the job yet.</p><p><strong>Key insights:</strong></p><ul><li>Replace customer satisfaction metrics with &quot;did the job get done?&quot; metrics</li><li>Replace NPS with &quot;reasons for hiring and firing&quot;</li><li>Replace feature usage metrics with &quot;progress on the job&quot;</li><li>When the job is poorly understood, integrate (control entire experience); when well understood, modularize (specialize components)</li><li>Integrate where performance is &quot;not good enough&quot; for the job; modularize where it&#39;s &quot;good enough&quot;</li><li>Every product decision should answer: &quot;Will this help the customer better accomplish their job?&quot;</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Metrics design</td><td>Define success metrics around job completion</td><td>Track &quot;time from problem to resolution&quot; instead of &quot;features used per session&quot;</td></tr><tr><td>Product roadmap</td><td>Prioritize based on job dimensions (functional, emotional, social)</td><td>A functional improvement that ignores the emotional dimension may not move the needle</td></tr><tr><td>Organizational alignment</td><td>Structure teams around jobs, not product components</td><td>A &quot;morning commute job&quot; team owns everything from content to packaging to distribution</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Built for [the job], not for [the category]&quot;</li><li>Emphasize outcome and progress, not features and specifications</li><li>&quot;Everything you need to [job] -- nothing you don&#39;t&quot;</li></ul><p><strong>Ethical boundary:</strong> Never design addictive patterns that serve engagement metrics rather than genuine customer progress. The job framework demands that the customer&#39;s progress is the true north, not your retention numbers.</p><p>See: <a href="./references/organizational-change">references/organizational-change.md</a></p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Why It Fails</th><th>Fix</th></tr></thead><tbody><tr><td>Defining jobs too narrowly around your product</td><td>You miss the real competitive landscape and build features no one needs</td><td>Define the job from the customer&#39;s perspective, never mentioning your product</td></tr><tr><td>Ignoring the emotional and social dimensions</td><td>Functional-only jobs miss why customers actually choose (and stay with) products</td><td>Always complete all three dimensions: functional, emotional, and social</td></tr><tr><td>Confusing jobs with goals or tasks</td><td>Goals are too abstract (&quot;be healthy&quot;) and tasks are too specific (&quot;click button&quot;) to drive strategy</td><td>Jobs describe progress in specific circumstances -- more concrete than goals, more strategic than tasks</td></tr><tr><td>Only increasing Pull while ignoring Anxiety and Habit</td><td>A great product still fails if switching costs and fear are too high</td><td>Map all four forces and design interventions for each, especially reducing anti-change forces</td></tr><tr><td>Winning the Big Hire but ignoring the Little Hire</td><td>High acquisition with high churn -- purchased but never used</td><td>Track and optimize the repeated usage decision separately from the purchase decision</td></tr><tr><td>Asking customers &quot;what do you want?&quot;</td><td>Customers rationalize and can&#39;t articulate latent needs; you get incremental feature requests</td><td>Use timeline-based discovery interviews that reconstruct actual behavior and decisions</td></tr><tr><td>Defining competition by product category</td><td>You miss the real threats and opportunities from adjacent categories and non-consumption</td><td>Map every alternative the customer could &quot;hire&quot; for the same job, including doing nothing</td></tr></tbody></table><h2 id="quick-diagnostic" tabindex="-1">Quick Diagnostic <a class="header-anchor" href="#quick-diagnostic" aria-label="Permalink to &quot;Quick Diagnostic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If No</th><th>Action</th></tr></thead><tbody><tr><td>Can you state the job in one sentence without mentioning your product?</td><td>You&#39;re product-focused, not job-focused</td><td>Write a job statement: &quot;When [circumstances], I want to [progress], so I can [outcome]&quot;</td></tr><tr><td>Have you mapped all four forces (Push, Pull, Anxiety, Habit)?</td><td>You&#39;re likely over-investing in Pull and ignoring barriers</td><td>Map each force and design specific interventions for Anxiety and Habit</td></tr><tr><td>Do you know the emotional and social dimensions of the job?</td><td>Your product may win functionally but lose on experience</td><td>Conduct discovery interviews focused on feelings and social context around the decision</td></tr><tr><td>Have you identified non-obvious competitors from other categories?</td><td>You have blind spots in your competitive landscape</td><td>List everything a customer could &quot;hire&quot; for the same job, including non-consumption</td></tr><tr><td>Are you tracking Little Hire separately from Big Hire?</td><td>You can&#39;t distinguish acquisition problems from retention problems</td><td>Create separate metrics for purchase conversion and repeated usage engagement</td></tr><tr><td>Can your team explain how a feature helps accomplish the job?</td><td>You&#39;re building features without strategic grounding</td><td>Require every feature proposal to reference the specific job dimension it serves</td></tr><tr><td>Have you interviewed customers about their purchase timeline?</td><td>Your understanding of the job is based on assumptions, not evidence</td><td>Conduct 10+ discovery interviews reconstructing the first-thought-to-usage journey</td></tr></tbody></table><p>See: <a href="./references/diagnostics">references/diagnostics.md</a> for the full diagnostic checklist.</p><h2 id="examples-and-case-studies" tabindex="-1">Examples and Case Studies <a class="header-anchor" href="#examples-and-case-studies" aria-label="Permalink to &quot;Examples and Case Studies&quot;">​</a></h2><p>See: <a href="./references/case-studies">references/case-studies.md</a> for detailed analyses (SNHU, American Girl, Intuit).</p><h2 id="reference-files" tabindex="-1">Reference Files <a class="header-anchor" href="#reference-files" aria-label="Permalink to &quot;Reference Files&quot;">​</a></h2><ul><li><a href="./references/innovation-process">innovation-process.md</a>: Job hunting methodology, job atlas, prototype testing, job statements</li><li><a href="./references/competitive-strategy">competitive-strategy.md</a>: Non-obvious competition, jobs-based positioning, pricing strategy</li><li><a href="./references/organizational-change">organizational-change.md</a>: Overcoming objections, feature-factory trap, executive buy-in, change management</li><li><a href="./references/diagnostics">diagnostics.md</a>: Diagnostic checklist for evaluating products through the jobs lens</li><li><a href="./references/case-studies">case-studies.md</a>: Detailed analyses of SNHU, American Girl, Intuit, and more</li></ul><h2 id="about-the-author" tabindex="-1">About the Author <a class="header-anchor" href="#about-the-author" aria-label="Permalink to &quot;About the Author&quot;">​</a></h2><p>Clayton M. Christensen (1952-2020) was the Kim B. Clark Professor of Business Administration at Harvard Business School and one of the most influential management thinkers of the modern era. He is best known for introducing the theory of disruptive innovation in his landmark book <em>The Innovator&#39;s Dilemma</em> (1997), which fundamentally changed how business leaders think about competition and market evolution. Christensen developed the Jobs to Be Done framework as a practical methodology for understanding customer motivation and driving successful innovation, detailed in <em>Competing Against Luck</em> (2016). He co-founded the innovation consulting firm Innosight and the Clayton Christensen Institute for Disruptive Innovation. Christensen was ranked the #1 management thinker in the world by Thinkers50 and received the award multiple times. His body of work, spanning nine books including <em>The Innovator&#39;s Solution</em> and <em>How Will You Measure Your Life?</em>, continues to shape product strategy, corporate innovation, and entrepreneurial thinking worldwide.</p><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><p>This skill is based on the Jobs to Be Done framework developed by Clayton M. Christensen. For the complete methodology, case studies, and deeper insights, read the original book:</p><ul><li><a href="https://www.amazon.com/Competing-Against-Luck-Innovation-Customer/dp/0062435612?tag=wondelai00-20" target="_blank" rel="noreferrer"><em>&quot;Competing Against Luck: The Story of Innovation and Customer Choice&quot;</em></a> by Clayton M. Christensen, Taddy Hall, Karen Dillon, and David S. Duncan</li></ul>',92)])])}const m=e(n,[["render",a]]);export{p as __pageData,m as default};
